// Extract the first summary document
const summaryDoc = $input.item.json.hits.hits[0]._source;
const clusterDoc = $('Split Clusters').item.json._source;

// Get cluster_id and ensure it's valid
let clusterId = summaryDoc.cluster_id || clusterDoc.cluster_id;

// Validate cluster_id - RETURN skip instead of throwing
if (clusterId === null || clusterId === undefined || clusterId === '' || isNaN(clusterId)) {
  const docId = $('Split Clusters').item.json._id;
  console.log(`⚠️ SKIPPING cluster with invalid ID: ${docId}, cluster_id value: ${clusterId}`);

  // Return skip object instead of throwing error
  return {
    json: {
      skip: true,
      reason: 'invalid_cluster_id',
      _cluster_doc_id: docId,
      cluster_id: null
    }
  };
}

// Parse cluster_id to integer
clusterId = parseInt(clusterId, 10);

// Validate it's a valid number after parsing
if (isNaN(clusterId)) {
  const docId = $('Split Clusters').item.json._id;
  console.log(`⚠️ SKIPPING cluster - cluster_id is NaN: ${docId}`);

  return {
    json: {
      skip: true,
      reason: 'cluster_id_is_nan',
      _cluster_doc_id: docId,
      cluster_id: null
    }
  };
}

// Clean and escape summary
let summary = summaryDoc.summary || summaryDoc.topic_label || 'No summary available';
summary = summary
  .replace(/[\r\n]+/g, ' ')
  .replace(/\s+/g, ' ')
  .trim();

// Return valid data
return {
  json: {
    cluster_id: clusterId,
    summary: summary,
    topic_label: summaryDoc.topic_label,
    article_count: parseInt(summaryDoc.article_count || clusterDoc.article_count || 1, 10),
    article_ids: summaryDoc.article_ids || clusterDoc.article_ids || [],
    _cluster_doc_id: $('Split Clusters').item.json._id
  }
};

// Get all items from the sub-workflow execution
const items = $input.all();

console.log('='.repeat(60));
console.log(`🔍 CONT LOOP DEBUG - Batch Info`);
console.log('='.repeat(60));
console.log(`Total items received: ${items.length}`);

// Log each item
items.forEach((item, index) => {
  const data = item.json;
  console.log(`\n--- Item ${index + 1}/${items.length} ---`);
  console.log(`Cluster ID: ${data.cluster_id || 'NULL'}`);
  console.log(`Had error: ${!!data.error}`);
  console.log(`Was skipped: ${data.skip === true}`);

  if (data.error) {
    console.log(`❌ ERROR DETAILS:`, data.error);
  }
});

// Count results
const errors = items.filter(i => i.json.error || i.json.cluster_id === null).length;
const success = items.length - errors;

console.log('\n' + '='.repeat(60));
console.log(`📊 BATCH SUMMARY`);
console.log(`✅ Successful: ${success}`);
console.log(`❌ Errors/Nulls: ${errors}`);
console.log('='.repeat(60));

// CRITICAL: Always return something valid, even if all items failed
// This ensures the loop continues
if (items.length === 0) {
  console.log(`⚠️ No items received, but continuing loop...`);
}

console.log(`🔄 Continuing to next batch...`);

// Return a simple continue signal
// Don't return the actual items - just a signal
return [{ json: { continue: true, batch_processed: items.length, errors: errors, success: success } }];

// Get clusters from Split Clusters node
let clustersToProcess = [];

try {
  const splitClusterItems = $('Split Clusters').all();

  if (splitClusterItems && splitClusterItems.length > 0) {
    console.log(`✅ Found ${splitClusterItems.length} clusters`);

    // Extract cluster info with article IDs
    clustersToProcess = splitClusterItems.map(item => {
      const source = item.json._source;
      return {
        cluster_id: source.cluster_id,
        article_ids: source.article_ids || [],
        _id: item.json._id
      };
    });
  } else {
    throw new Error('Split Clusters returned no items');
  }
} catch (e) {
  console.error('❌ Error getting clusters:', e.message);
  throw new Error('No cluster data available from Split Clusters');
}

// Get all unique article IDs across all clusters
const allArticleIds = [...new Set(clustersToProcess.flatMap(c => c.article_ids))];

console.log('='.repeat(60));
console.log('📊 EXTRACTED ARTICLE IDs FOR OPENSEARCH');
console.log('='.repeat(60));
console.log(`Total clusters: ${clustersToProcess.length}`);
console.log(`Unique article IDs: ${allArticleIds.length}`);
console.log(`Article IDs:`, allArticleIds.slice(0, 10), allArticleIds.length > 10 ? '...' : '');
console.log('='.repeat(60));


console.log(`📋 Querying ${allArticleIds.length} articles from article_summaries`);

// Return single item with all article IDs
return [{
  json: {
    article_ids: allArticleIds
  }
}];

// Get the OpenSearch response with article summaries
const input = $input.item.json;

// Extract article summaries from the hits
let articleSummaries = {};
let foundArticleIds = [];
let articleLanguages = {}; // Store languages per article

if (input.hits && input.hits.hits && input.hits.hits.length > 0) {
  input.hits.hits.forEach(hit => {
    const source = hit._source;
    const articleId = source.article_id;
    const summary = source.summary;
    const language = source.language;

    if (articleId && summary) {
      articleSummaries[articleId] = summary;
      articleLanguages[articleId] = language || 'en';
      foundArticleIds.push(articleId);
    }
  });

  console.log(`✅ Found ${Object.keys(articleSummaries).length} article summaries from OpenSearch`);
} else {
  console.warn('⚠️ No article summaries found in OpenSearch response');
}

// Get the clusters data (from Split Clusters node)
let clustersRaw = [];
try {
  const splitClusterItems = $('Split Clusters').all();

  if (splitClusterItems && splitClusterItems.length > 0) {
    clustersRaw = splitClusterItems.map(item => {
      const source = item.json._source;
      return {
        cluster_id: source.cluster_id,
        article_ids: source.article_ids || [],
        _id: item.json._id
      };
    });
    console.log(`✅ Found ${clustersRaw.length} raw clusters`);
  }
} catch (e) {
  console.error('❌ Error getting clusters:', e.message);
  throw new Error('No cluster data available from Split Clusters');
}

// Clean and validate clusters
const clusters = [];
const seenClusterIds = new Set();
let skippedClusters = 0;

clustersRaw.forEach(cluster => {
  const rawClusterId = cluster.cluster_id;
  const articleIds = cluster.article_ids || [];

  // Skip if cluster_id is invalid (null, undefined, or empty string)
  if (rawClusterId === null || rawClusterId === undefined || rawClusterId === '' || rawClusterId === 'undefined') {
    console.warn(`⚠️ Skipping cluster with invalid ID: ${cluster._id}`);
    skippedClusters++;
    return;
  }

  // Skip if no articles
  if (articleIds.length === 0) {
    console.warn(`⚠️ Skipping cluster ${rawClusterId} - no articles`);
    skippedClusters++;
    return;
  }

  // ALWAYS convert to string (API requires string)
  const clusterId = String(rawClusterId);

  // Skip duplicates
  if (seenClusterIds.has(clusterId)) {
    console.warn(`⚠️ Skipping duplicate cluster_id: ${clusterId}`);
    skippedClusters++;
    return;
  }

  seenClusterIds.add(clusterId);

  // Add valid cluster
  clusters.push({
    cluster_id: clusterId, // ALWAYS STRING
    article_ids: articleIds
  });
});

console.log(`✅ Validated ${clusters.length} clusters (skipped ${skippedClusters})`);

// Get all unique article IDs from clusters
const allArticleIds = [...new Set(clusters.flatMap(c => c.article_ids))];
console.log(`📋 Total unique articles in clusters: ${allArticleIds.length}`);

// Build articles array
const articles = allArticleIds.map(articleId => ({
  id: articleId,
  title: '', // Will be filled by LLM service
  body: articleSummaries[articleId] || '', // Use cached summary as body
  language: articleLanguages[articleId] || 'en'
}));

// Check coverage
const articlesWithSummaries = allArticleIds.filter(id => articleSummaries[id]).length;
const articlesWithoutSummaries = allArticleIds.length - articlesWithSummaries;
const missingIds = allArticleIds.filter(id => !articleSummaries[id]);

console.log('\n' + '='.repeat(60));
console.log('📊 PAYLOAD SUMMARY FOR CLUSTER_SUMMARY_FROM_CLUSTERS');
console.log('='.repeat(60));
console.log(`Valid clusters to process: ${clusters.length}`);
console.log(`Skipped invalid clusters: ${skippedClusters}`);
console.log(`Total articles: ${allArticleIds.length}`);
console.log(`Articles with cached summaries: ${articlesWithSummaries}`);
console.log(`Articles needing new summaries: ${articlesWithoutSummaries}`);

if (missingIds.length > 0) {
  console.log(`\n⚠️ Missing summaries for ${missingIds.length} articles:`);
  console.log(missingIds.slice(0, 10).join(', '), missingIds.length > 10 ? '...' : '');
}
console.log('='.repeat(60));

// Validate
if (clusters.length === 0) {
  throw new Error('No valid clusters to process after filtering');
}

if (allArticleIds.length === 0) {
  throw new Error('No articles in clusters');
}

// Prepare the request payload
const requestId = `req_cluster_summary_${Date.now()}`;
const payload = {
  request_id: requestId,
  clusters: clusters,
  articles: articles,
  article_summaries: articleSummaries
};

console.log(`\n📤 Payload ready for /cluster_summary_from_clusters`);
console.log(`Request ID: ${requestId}`);
console.log(`Will use ${articlesWithSummaries} cached summaries, generate ${articlesWithoutSummaries} new ones`);

return [{ json: payload }];

// Get the prepared payload from previous node
const input = $input.item.json;

const clusters = input.clusters;
const articles = input.articles;
const articleSummaries = input.article_summaries;

// Define batch size (how many clusters to process in parallel)
const BATCH_SIZE = 5; // Adjust based on your LLM service capacity

console.log(`Creating batches for ${clusters.length} clusters`);
console.log(`Batch size: ${BATCH_SIZE}`);

// Calculate total batches
const totalBatches = Math.ceil(clusters.length / BATCH_SIZE);

// Create batches
const batches = [];
for (let i = 0; i < clusters.length; i += BATCH_SIZE) {
  const batchClusters = clusters.slice(i, i + BATCH_SIZE);

  // Get article IDs for this batch
  const batchArticleIds = [...new Set(batchClusters.flatMap(c => c.article_ids))];

  // Filter articles for this batch
  const batchArticles = articles.filter(a => batchArticleIds.includes(a.id));

  // Filter summaries for this batch
  const batchSummaries = {};
  batchArticleIds.forEach(id => {
    if (articleSummaries[id]) {
      batchSummaries[id] = articleSummaries[id];
    }
  });

  const batchNum = Math.floor(i / BATCH_SIZE) + 1;

  batches.push({
    batch_number: batchNum,
    total_batches: totalBatches,
    request_id: `${input.request_id}_batch_${batchNum}`,
    clusters: batchClusters,
    articles: batchArticles,
    article_summaries: batchSummaries
  });

  console.log(`Batch ${batchNum}/${totalBatches}: ${batchClusters.length} clusters, ${batchArticles.length} articles`);
}

console.log(`\n✅ Created ${batches.length} batches`);
console.log(`Outputting ${batches.length} separate items for parallel processing`);

// CRITICAL: Return array directly - n8n will convert each element to a separate item
return batches;
